<script lang="ts">
	import { afterNavigate } from "$app/navigation";
	import { page } from "$app/stores";
	import { AppBar,drawerStore,storeLightSwitch, tooltip, type DrawerSettings} from "@skeletonlabs/skeleton";
	import { onDestroy, onMount } from "svelte";

    let main: HTMLElement | null;
    let yScroll: number = 0;
    function scrollHandler(e: any): void {
        yScroll = e.target.scrollTop;
    }
    onMount(() => {
        main = document.getElementById('page');
        if (main) main.addEventListener('scroll', scrollHandler);
    });

    onDestroy(() => {
        if (main) main.removeEventListener('scroll', scrollHandler);
    });

    afterNavigate(() => {
        if (main) main.scrollTop = 0;
    });
    
	const toggleTheme = () => {
		storeLightSwitch.update(state => {return !state});
		const elemHtmlClassList = document.documentElement.classList;
		$storeLightSwitch ? elemHtmlClassList.add('dark') : elemHtmlClassList.remove('dark');
	}

    const toggleThemeToolTipProps = { 
        content: 'Toggle Theme', 
        position: 'bottom', 
        background: '!bg-surface-200-700-token',
        width: '!w-32',
    }

    const hamburgerToolTipProps = { 
        content: 'Open Navbar', 
        position: 'bottom', 
        background: '!bg-surface-200-700-token',
        width: '!w-32',
    }

    const openHamburger = () => {
        const settings: DrawerSettings = {
            id: 'hamburger',
            position: 'right',
            width: 'w-[min(75vw,25rem)]'
        };
        drawerStore.open(settings);
    }
</script>

